CREATE OR REPLACE FUNCTION fn_update_tickets_sold()
RETURNS TRIGGER AS $$
DECLARE
    affected_session_id BIGINT;
BEGIN
    IF TG_OP = 'DELETE' THEN
        affected_session_id := OLD.session_id;
    ELSE
        affected_session_id := NEW.session_id;
    END IF;

    UPDATE cinema_session
    SET tickets_sold    = (
            SELECT COUNT(*) FROM ticket
            WHERE session_id = affected_session_id
              AND status != 'CANCELLED'
        ),
        seats_available = total_seats - (
            SELECT COUNT(*) FROM ticket
            WHERE session_id = affected_session_id
              AND status != 'CANCELLED'
        )
    FROM hall
    WHERE cinema_session.id      = affected_session_id
      AND cinema_session.hall_id = hall.id;

    RETURN NULL;
END;
$$ LANGUAGE plpgsql;
